function scopeDemo() {
  if (true) {
    var functionScoped = 'accessible anywhere in function';
    let blockScoped = 'only accessible in this block';
    const alsoBlockScoped = 'same as let';
  }

  console.log(functionScoped);  // 'accessible anywhere in function'
  // console.log(blockScoped);  // ReferenceError: blockScoped is not defined
  // console.log(alsoBlockScoped); // ReferenceError

  // var 'leaks' out of the if block
  // let/const stay contained within the block
}

scopeDemo();

// At the global level:
// console.log(functionScoped); // ReferenceError (function scope)

// Key takeaway: let and const are BLOCK-scoped
// var is FUNCTION-scoped

// var: single binding for all iterations
const varCallbacks = [];
for (var i = 0; i < 3; i++) {
  varCallbacks.push(() => console.log('var:', i));
}
varCallbacks.forEach(cb => cb());
// Output: var: 3, var: 3, var: 3

// let: new binding per iteration
const letCallbacks = [];
for (let j = 0; j < 3; j++) {
  letCallbacks.push(() => console.log('let:', j));
}
letCallbacks.forEach(cb => cb());
// Output: let: 0, let: 1, let: 2

// let effectively does:
// { let j = 0; callbacks.push(() => j); }
// { let j = 1; callbacks.push(() => j); }
// { let j = 2; callbacks.push(() => j); }

const planet = 'Earth';  // Level 0: Global scope

function outer() {
  const galaxy = 'Milky Way';  // Level 1: outer's scope

  function inner() {
    const solarSystem = 'Solar System';  // Level 2: inner's scope

    // Variable resolution starts at the innermost scope
    console.log(solarSystem);  // Found in Level 2
    console.log(galaxy);       // Not in Level 2, check Level 1 -> found
    console.log(planet);       // Not in Level 2 or 1, check Level 0 -> found
  }

  inner();
}

outer();

// Scope chain for inner:
// inner's scope -> outer's scope -> global scope
// inner can access: solarSystem, galaxy, planet
// outer can access: galaxy, planet
// Global can access: planet only

let name = 'Global Alice';

function shadowDemo() {
  let name = 'Local Bob';  // Shadows the global 'name'
  console.log(name);  // 'Local Bob' (inner scope wins)

  function deeplyNested() {
    let name = 'Deep Charlie';  // Shadows both
    console.log(name);  // 'Deep Charlie'
  }

  deeplyNested();
  console.log(name);  // 'Local Bob' (back to middle scope)
}

shadowDemo();
console.log(name);  // 'Global Alice' (global unchanged)

// Shadowing is not the same as mutation!
// Each 'name' is a SEPARATE variable in its own scope.
// The global 'name' was never modified.

// Before ES6 block scoping, IIFEs were used to create private scopes

// Global scope
const globalValue = 'I am global';

// IIFE creates a new function scope
(function() {
  // This variable is scoped to the IIFE, not global
  const privateValue = 'I am private to the IIFE';
  var alsoPrivate = 'Also private (var in function scope)';

  console.log(globalValue);  // 'I am global' (accessible via scope chain)
  console.log(privateValue); // 'I am private to the IIFE'
})();

// console.log(privateValue);  // ReferenceError
// console.log(alsoPrivate);   // ReferenceError

// Modern alternative: just use a block
{
  let modernPrivate = 'Block scoped!';
  console.log(modernPrivate); // 'Block scoped!'
}
// console.log(modernPrivate); // ReferenceError
